class Solution {
    public boolean isRationalEqual(String s, String t) {
        return getDouble(s) == getDouble(t);
    }

    private double getDouble(String s) {
        int index = s.indexOf('(');
        if (index == -1) {
            return Double.parseDouble(s);
        } else {
            int start = s.indexOf('.');
            int end = s.indexOf(')');
            String integerPart = s.substring(0, start);
            String nonRepeatingPart = s.substring(start + 1, index);
            String repeatingPart = s.substring(index + 1, end);
            double nonRepeatingValue = Double.parseDouble(integerPart + "." + nonRepeatingPart);
            double repeatingValue = Double.parseDouble("0." + repeatingPart) / (Math.pow(10, repeatingPart.length()) - 1);
            return nonRepeatingValue + repeatingValue;
        }
    }
}
